const KEY="brick_buddy_2_0";

function defaultState(){
  return {
    profile:{learner:"",employer:"",assessor:"",course:"Carpentry and Joinery Level 2"},
    evidence:{},
    otj:[],
    practical:{},
    quizHistory:[],
    wrong:[],
    documents:[],
    lastAssignment:1,
    settings:{darkMode:false},
    epaPracticalMock:{learner:{},assessor:{},comments:""},
    epaDiscussionMock:{learner:{},assessor:{},comments:""}
  };
}

function loadState(){
  let state=defaultState();
  try{
    const saved=JSON.parse(localStorage.getItem(KEY));
    if(saved) state={...state,...saved};
  }catch{}
  state.profile ||= {};
  state.evidence ||= {};
  state.otj ||= [];
  state.practical ||= {};
  state.quizHistory ||= [];
  state.wrong ||= [];
  state.documents ||= [];
  state.settings ||= {darkMode:false};
  state.epaPracticalMock ||= {learner:{},assessor:{},comments:""};
  state.epaDiscussionMock ||= {learner:{},assessor:{},comments:""};
  return state;
}

function saveState(state){
  localStorage.setItem(KEY,JSON.stringify(state));
}

function exportBackup(state){
  const blob=new Blob([JSON.stringify(state,null,2)],{type:"application/json"});
  const url=URL.createObjectURL(blob);
  const a=document.createElement("a");
  a.href=url;
  a.download="Bench-Buddy-Backup.json";
  a.click();
  URL.revokeObjectURL(url);
}


const DB_NAME="brick_buddy_2_files";
const STORE_NAME="images";

function openDb(){
  return new Promise((resolve,reject)=>{
    const request=indexedDB.open(DB_NAME,1);
    request.onupgradeneeded=()=>{
      if(!request.result.objectStoreNames.contains(STORE_NAME)){
        request.result.createObjectStore(STORE_NAME);
      }
    };
    request.onsuccess=()=>resolve(request.result);
    request.onerror=()=>reject(request.error);
  });
}

async function putImage(key,value){
  const db=await openDb();
  return new Promise((resolve,reject)=>{
    const tx=db.transaction(STORE_NAME,"readwrite");
    tx.objectStore(STORE_NAME).put(value,key);
    tx.oncomplete=resolve;
    tx.onerror=()=>reject(tx.error);
  });
}

async function getImage(key){
  const db=await openDb();
  return new Promise((resolve,reject)=>{
    const req=db.transaction(STORE_NAME,"readonly").objectStore(STORE_NAME).get(key);
    req.onsuccess=()=>resolve(req.result);
    req.onerror=()=>reject(req.error);
  });
}

function resizeImage(file,maxWidth=1400,quality=.76){
  return new Promise((resolve,reject)=>{
    const reader=new FileReader();
    reader.onload=()=>{
      const img=new Image();
      img.onload=()=>{
        const scale=Math.min(1,maxWidth/img.width);
        const canvas=document.createElement("canvas");
        canvas.width=Math.round(img.width*scale);
        canvas.height=Math.round(img.height*scale);
        canvas.getContext("2d").drawImage(img,0,0,canvas.width,canvas.height);
        resolve(canvas.toDataURL("image/jpeg",quality));
      };
      img.onerror=reject;
      img.src=reader.result;
    };
    reader.onerror=reject;
    reader.readAsDataURL(file);
  });
}


async function putFile(key,file){
  const db=await openDb();
  return new Promise((resolve,reject)=>{
    const tx=db.transaction(STORE_NAME,"readwrite");
    tx.objectStore(STORE_NAME).put(file,key);
    tx.oncomplete=resolve;
    tx.onerror=()=>reject(tx.error);
  });
}

async function getFile(key){
  return getImage(key);
}


const ukDate=value=>{
  if(!value)return "";
  const [y,m,d]=value.split("-");
  return `${d}/${m}/${y}`;
};

const sentence=text=>{
  const clean=(text||"").trim();
  if(!clean)return "";
  return /[.!?]$/.test(clean)?clean:`${clean}.`;
};

function cleanSkillLabel(text){
  let label=String(text||"").replace(/^show\s+/i,"").replace(/^the\s+/i,"").replace(/\.$/,"").trim();
  const patterns=[
    [/risk assessment|rams/i,"RAMS"],[/cutting list/i,"Cutting list"],
    [/personal protective equipment|\bppe\b/i,"PPE"],[/respiratory protective equipment|\brpe\b/i,"RPE"],
    [/local exhaust ventilation|\blev\b/i,"LEV"],[/drawing|working drawing/i,"Drawing"],
    [/specification/i,"Specification"],[/material list/i,"Material list"],[/toolbox talk/i,"Toolbox talk"],
    [/site induction/i,"Site induction"],[/hand tools?/i,"Hand tools"],[/power tools?/i,"Power tools"],
    [/machine setup|machine setting/i,"Machine setup"],[/guards?/i,"Guarding"],[/dust extraction|extraction/i,"Extraction"],
    [/marking out|setting out/i,"Setting out"],[/measurements?|dimensions?/i,"Measurements"],
    [/timber selection|material selection/i,"Material selection"],[/safe working|working safely/i,"Safe working"],
    [/quality checks?|checking the finished work/i,"Quality checks"],[/joint/i,"Joint construction"],
    [/assembly/i,"Assembly"],[/clamping/i,"Clamping"],[/adhesive/i,"Adhesive"],
    [/surface preparation/i,"Surface preparation"],[/abrasives?/i,"Abrasives"],[/finish/i,"Finish"],
    [/fire door/i,"Fire door requirements"],[/seals?/i,"Seals"],[/ironmongery/i,"Ironmongery"],
    [/communication/i,"Communication"],[/teamwork/i,"Teamwork"],[/professional/i,"Professional behaviour"]
  ];
  for(const [pattern,replacement] of patterns){if(pattern.test(label))return replacement;}
  label=label.replace(/\bbeing\b.*$/i,"").replace(/\bused\b.*$/i,"").replace(/\bcompleted\b.*$/i,"")
    .replace(/\binstalled\b.*$/i,"").replace(/\bprepared\b.*$/i,"").replace(/\s+/g," ").trim();
  if(label.length>34)label=label.slice(0,34).replace(/\s+\S*$/,"");
  return label.charAt(0).toUpperCase()+label.slice(1);
}
function termFromLabel(label){
  const map={"RAMS":"rams","Cutting list":"cutting list","PPE":"ppe","RPE":"rpe","LEV":"lev","Drawing":"drawing",
  "Specification":"specification","Material list":"material list","Toolbox talk":"toolbox talk","Site induction":"site induction",
  "Hand tools":"hand tools","Power tools":"power tools","Machine setup":"setup","Guarding":"guard","Extraction":"extraction",
  "Setting out":"setting out","Measurements":"measur","Material selection":"material","Safe working":"safe",
  "Quality checks":"check","Joint construction":"joint","Assembly":"assembl","Clamping":"clamp","Adhesive":"adhesive",
  "Surface preparation":"prepar","Abrasives":"abrasive","Finish":"finish","Fire door requirements":"fire door",
  "Seals":"seal","Ironmongery":"ironmongery","Communication":"communicat","Teamwork":"team","Professional behaviour":"professional"};
  return map[label]||label.toLowerCase();
}
function assignmentSkillPrompts(assignment){
  const prompts=(assignment.photos||[]).slice(0,3).map(text=>{
    const label=cleanSkillLabel(text);
    return {label,term:termFromLabel(label),source:text};
  });
  while(prompts.length<3){
    const fallback=["Method","Tools","Quality checks"][prompts.length];
    prompts.push({label:fallback,term:termFromLabel(fallback),source:fallback});
  }
  return prompts.slice(0,3);
}


const promptStopWords=new Set([
  "explain","describe","what","which","when","where","how","why","this","that","with","from","into",
  "should","would","could","your","work","used","using","during","before","after","activity","product",
  "completed","complete","required","needed","linked","demonstrated","finished","bench","joinery"
]);

function wordsFromQuestion(question){
  const original=String(question||"");
  const cleaned=original.toLowerCase().replace(/[^a-z0-9\s-]/g," ");
  const exactTerms=[
    [/\bPPE\b/i,"PPE","ppe"],[/\bRPE\b/i,"RPE","rpe"],[/\bLEV\b/i,"LEV","lev"],
    [/\bRAMS\b/i,"RAMS","rams"],[/\bCOSHH\b/i,"COSHH","coshh"],[/\bPUWER\b/i,"PUWER","puwer"],
    [/risk assessment/i,"Risk assessment","risk assessment"],[/method statement/i,"Method statement","method statement"],
    [/safe system of work/i,"Safe system","safe system"],[/local exhaust ventilation/i,"LEV","lev"],
    [/personal protective equipment/i,"PPE","ppe"],[/respiratory protective equipment/i,"RPE","rpe"],
    [/guarding/i,"Guarding","guard"],[/hand tools?/i,"Hand tools","hand tools"],[/power tools?/i,"Power tools","power tools"],
    [/dust extraction/i,"Extraction","extraction"],[/drawing/i,"Drawing","drawing"],[/specification/i,"Specification","specification"],
    [/measurements?/i,"Measurements","measur"],[/dimensions?/i,"Dimensions","dimension"],[/tolerances?/i,"Tolerances","tolerance"],
    [/materials?/i,"Materials","material"],[/waste/i,"Waste","waste"],[/recycl/i,"Recycling","recycl"],
    [/environment/i,"Environment","environment"],[/maintenance/i,"Maintenance","maintenance"],[/defects?/i,"Defects","defect"],
    [/quality/i,"Quality","quality"],[/communication/i,"Communication","communicat"],[/teamwork/i,"Teamwork","team"],
    [/professional/i,"Professional behaviour","professional"],[/fire door/i,"Fire door","fire door"],[/seals?/i,"Seals","seal"],
    [/ironmongery/i,"Ironmongery","ironmongery"],[/adhesive/i,"Adhesive","adhesive"],[/clamping/i,"Clamping","clamp"],
    [/joint/i,"Joint","joint"],[/assembly/i,"Assembly","assembl"],[/surface preparation/i,"Surface preparation","prepar"],
    [/abrasives?/i,"Abrasives","abrasive"],[/finish/i,"Finish","finish"]
  ];
  const chosen=[];
  exactTerms.forEach(([pattern,label,term])=>{
    if(pattern.test(original)&&!chosen.some(x=>x.term===term)&&chosen.length<3)chosen.push({label,term});
  });
  if(chosen.length<3){
    cleaned.split(/\s+/).forEach(word=>{
      if(chosen.length>=3||word.length<5||promptStopWords.has(word))return;
      const stem=word.replace(/(ing|ed|es|s)$/,"");
      if(!chosen.some(x=>x.term===stem))chosen.push({label:word.charAt(0).toUpperCase()+word.slice(1),term:stem});
    });
  }
  [{label:"Reason",term:"because"},{label:"Method",term:"method"},{label:"Safe practice",term:"safe"}]
    .forEach(x=>{if(chosen.length<3&&!chosen.some(y=>y.term===x.term))chosen.push(x)});
  return chosen.slice(0,3);
}


function ensureCombinedEvidence(evidence={},assignment=null){
  evidence.evidenceItems ||= [];
  if(!evidence._combinedMigrated){
    const prompts=assignment?assignmentSkillPrompts(assignment):[];
    Object.values(evidence.photos||{}).forEach((item,index)=>{
      if(item?.imageKey&&!evidence.evidenceItems.some(x=>x.key===item.imageKey)){
        evidence.evidenceItems.push({key:item.imageKey,imageKey:item.imageKey,
          name:prompts[index]?.label||`Skill evidence ${Number(index)+1}`,type:"image/jpeg",isImage:true});
      }
    });
    (evidence.additionalPhotos||[]).forEach((item,index)=>{
      if(item?.imageKey&&!evidence.evidenceItems.some(x=>x.key===item.imageKey)){
        evidence.evidenceItems.push({key:item.imageKey,imageKey:item.imageKey,
          name:`Supporting evidence ${Number(index)+1}`,type:"image/jpeg",isImage:true});
      }
    });
    if(!evidence.description){
      evidence.description=Object.values(evidence.photos||{}).map(x=>x?.explanation||"").filter(Boolean).join("\n\n");
    }
    evidence._combinedMigrated=true;
  }
  if(assignment){
    const prompts=assignmentSkillPrompts(assignment);
    evidence.evidenceItems.forEach((item,index)=>{
      if(index<3&&item.isImage&&(!item.name||/^Required photograph/i.test(item.name)||/^Skill evidence/i.test(item.name))){
        item.name=prompts[index]?.label||`Skill evidence ${index+1}`;
      }
    });
  }
  evidence.answers ||= {};
  return evidence;
}


function normalisePromptWord(word){
  let w=String(word||"").toLowerCase().replace(/[^a-z0-9]/g,"");
  if(w.length>5&&w.endsWith("ies"))w=w.slice(0,-3)+"y";
  else if(w.length>5&&w.endsWith("ing"))w=w.slice(0,-3);
  else if(w.length>4&&w.endsWith("ed"))w=w.slice(0,-2);
  else if(w.length>4&&w.endsWith("es"))w=w.slice(0,-2);
  else if(w.length>3&&w.endsWith("s"))w=w.slice(0,-1);
  return w;
}

function promptMatched(text,term){
  const source=String(text||"").toLowerCase().trim();
  const target=String(term||"").toLowerCase().trim();
  if(!source||!target)return false;

  const sourceWords=source
    .replace(/[^a-z0-9\s-]/g," ")
    .split(/\s+/)
    .filter(Boolean);

  const targetWords=target
    .replace(/[^a-z0-9\s-]/g," ")
    .split(/\s+/)
    .filter(Boolean);

  if(!targetWords.length)return false;

  // Exact phrase first, including plural or tense variations word-by-word.
  if(targetWords.length>1){
    for(let i=0;i<=sourceWords.length-targetWords.length;i++){
      const phraseMatches=targetWords.every((word,index)=>{
        const sourceWord=sourceWords[i+index];
        return sourceWord===word||
          normalisePromptWord(sourceWord)===normalisePromptWord(word);
      });
      if(phraseMatches)return true;
    }
    return false;
  }

  const wanted=normalisePromptWord(targetWords[0]);
  return sourceWords.some(word=>{
    const normalised=normalisePromptWord(word);
    return word===targetWords[0]||normalised===wanted;
  });
}

