function reflectionTopics(assignment){
  const refs=assignmentKsbMap[String(assignment.id)]||[];
  const knowledgeRefs=refs.filter(x=>x.startsWith("K"));
  const behaviourRefs=refs.filter(x=>x.startsWith("B"));

  return (assignment.statementQuestions||[]).map((question,index)=>{
    const isBehaviour=index===(assignment.statementQuestions.length-1);
    const ref=isBehaviour
      ? (behaviourRefs.join(", ")||"Behaviour")
      : (knowledgeRefs[index]||knowledgeRefs[Math.min(index,knowledgeRefs.length-1)]||`Knowledge ${index+1}`);

    const title=reflectionTopicTitle(question,index);
    const extracted=wordsFromQuestion(question);
    const simplePrompts=extracted.slice(0,2).map(p=>({
      label:p.label,
      term:p.term
    }));

    while(simplePrompts.length<2){
      const fallback=simplePrompts.length===0
        ? {label:"Explain clearly",term:"because"}
        : {label:"Give an example",term:"example"};
      simplePrompts.push(fallback);
    }

    return {ref,title,question,prompts:simplePrompts};
  });
}


function uniquePrompts(prompts){
  const seen=new Set();
  return (prompts||[]).filter(prompt=>{
    const key=String(prompt.term||prompt.label||'').toLowerCase();
    if(!key||seen.has(key))return false;
    seen.add(key);
    return true;
  });
}

function combinedReflectionPrompts(assignment){
  return uniquePrompts(reflectionTopics(assignment).flatMap(topic=>topic.prompts));
}

function reflectionTopicSentence(assignment){
  const titles=[...new Set(reflectionTopics(assignment).map(topic=>topic.title))];
  if(!titles.length)return 'professional knowledge and behaviours';
  if(titles.length===1)return titles[0].toLowerCase();
  return `${titles.slice(0,-1).map(x=>x.toLowerCase()).join(', ')} and ${titles.at(-1).toLowerCase()}`;
}

function promptRegexSource(prompt){
  const values=[prompt.label,prompt.term].filter(Boolean).map(value=>String(value).trim());
  const aliases={
    ppe:['PPE','personal protective equipment'],
    rpe:['RPE','respiratory protective equipment'],
    lev:['LEV','local exhaust ventilation'],
    rams:['RAMS','risk assessment','method statement'],
    communicat:['communication','communicated','discussed','explained'],
    team:['team','teamwork','colleague','colleagues','working together'],
    safe:['safe','safely','safe working'],
    measur:['measure','measured','measurement','measurements','measuring'],
    prepar:['prepare','prepared','preparation','preparing'],
    assembl:['assemble','assembled','assembly','assembling'],
    recycl:['recycle','recycled','recycling'],
    check:['check','checked','checks','checking','quality check','quality checks']
  };
  (aliases[String(prompt.term||'').toLowerCase()]||[]).forEach(value=>values.push(value));
  return [...new Set(values)].sort((a,b)=>b.length-a.length).map(value=>{
    const escaped=value.replace(/[.*+?^${}()|[\]\\]/g,'\\$&');
    return escaped.length<=5&&!escaped.includes('\\ ')?`\\b${escaped}\\w*\\b`:`\\b${escaped}\\b`;
  }).join('|');
}

function highlightedSegments(text,prompts){
  const sources=uniquePrompts(prompts).map(promptRegexSource).filter(Boolean);
  if(!sources.length)return [{text:String(text||''),bold:false}];
  const regex=new RegExp(`(${sources.join('|')})`,'gi');
  const segments=[];let last=0;const value=String(text||'');let match;
  while((match=regex.exec(value))){
    if(match.index>last)segments.push({text:value.slice(last,match.index),bold:false});
    segments.push({text:match[0],bold:true});last=match.index+match[0].length;
    if(regex.lastIndex===match.index)regex.lastIndex++;
  }
  if(last<value.length)segments.push({text:value.slice(last),bold:false});
  return segments;
}

function drawHighlightedText(pdf,text,prompts,x,y,maxWidth,lineHeight=4.2,newPage=null){
  const segments=highlightedSegments(text,prompts);
  let cursorX=x,cursorY=y;
  const tokens=[];
  segments.forEach(segment=>{
    String(segment.text).split(/(\s+|\n)/).forEach(token=>{if(token!=='')tokens.push({text:token,bold:segment.bold})});
  });
  for(const token of tokens){
    if(token.text.includes('\n')){
      const pieces=token.text.split('\n');
      for(let i=0;i<pieces.length;i++){
        if(pieces[i]){
          pdf.setFont('helvetica',token.bold?'bold':'normal');
          const width=pdf.getTextWidth(pieces[i]);
          if(cursorX+width>x+maxWidth){cursorX=x;cursorY+=lineHeight;}
          if(newPage&&cursorY>276){cursorY=newPage();cursorX=x;}
          pdf.text(pieces[i],cursorX,cursorY);cursorX+=width;
        }
        if(i<pieces.length-1){cursorX=x;cursorY+=lineHeight;if(newPage&&cursorY>276)cursorY=newPage();}
      }
      continue;
    }
    pdf.setFont('helvetica',token.bold?'bold':'normal');
    const width=pdf.getTextWidth(token.text);
    if(cursorX+width>x+maxWidth&&!/^\s+$/.test(token.text)){cursorX=x;cursorY+=lineHeight;if(newPage&&cursorY>276)cursorY=newPage();}
    if(!(cursorX===x&&/^\s+$/.test(token.text))){pdf.text(token.text,cursorX,cursorY);cursorX+=width;}
  }
  return cursorY+lineHeight;
}


function allRequiredPromptsMet(assignment,evidence){
  const activity=assignmentEvidencePrompts(assignment);
  const reflection=combinedReflectionPrompts(assignment);
  return {
    activityOk:activity.every(p=>promptMatchedWithAliases(evidence.description||"",p.term)),
    reflectionOk:reflection.every(p=>promptMatchedWithAliases(evidence.reflection||"",p.term))
  };
}

function ensurePortfolioReflection(evidence={}){
  if(!evidence.reflection){
    evidence.reflection=Object.values(evidence.answers||{}).filter(Boolean).join("\n\n");
  }
  return evidence;
}

function assignmentStatus(assignment,evidence={}){
  evidence=ensurePortfolioReflection(ensureCombinedEvidence(evidence,assignment));
  const itemCount=(evidence.evidenceItems||[]).filter(x=>x?.key).length;
  const descriptionWords=wordCount(evidence.description);
  const reflectionWords=wordCount(evidence.reflection);
  const promptState=allRequiredPromptsMet(assignment,evidence);
  const descriptionDone=descriptionWords>=150;
  const reflectionDone=reflectionWords>=150;
  const requiredDone=itemCount>=3&&descriptionDone&&promptState.activityOk;
  const answersDone=reflectionDone&&promptState.reflectionOk;
  const hasAny=itemCount>0||descriptionWords>0||reflectionWords>0;
  const pdfGenerated=state.documents?.some(x=>x.type==="Assignment Evidence Pack"&&x.assignmentId===assignment.id);
  return {
    photosDone:Math.min(itemCount,3),itemCount,descriptionWords,reflectionWords,
    descriptionDone,reflectionDone,promptState,requiredDone,answersDone,hasAny,pdfGenerated,
    complete:requiredDone&&answersDone
  };
}
function shuffleQuestion(original){
  const correctText=original.options[original.answer];
  const unknown=original.options.find(x=>x.toLowerCase().includes("don't know"));
  const normal=original.options.filter(x=>x!==unknown);
  for(let i=normal.length-1;i>0;i--){
    const j=Math.floor(Math.random()*(i+1));
    [normal[i],normal[j]]=[normal[j],normal[i]];
  }
  const options=unknown?[...normal,unknown]:normal;
  return {...original,options,answer:options.indexOf(correctText)};
}

